import{_ as e,o as l,c as a,ag as n}from"./chunks/framework.DXGyWiRo.js";const x=JSON.parse('{"title":"知识点3：数据压缩","description":"","frontmatter":{"title":"知识点3：数据压缩"},"headers":[],"relativePath":"high-school-it/knowledge-3.md","filePath":"high-school-it/knowledge-3.md"}'),r={name:"high-school-it/knowledge-3.md"};function d(i,t,o,s,h,g){return l(),a("div",null,[...t[0]||(t[0]=[n('<h1 id="知识点3-数据压缩" tabindex="-1">知识点3：数据压缩 <a class="header-anchor" href="#知识点3-数据压缩" aria-label="Permalink to &quot;知识点3：数据压缩&quot;">​</a></h1><h2 id="一、基本概念" tabindex="-1">一、基本概念 <a class="header-anchor" href="#一、基本概念" aria-label="Permalink to &quot;一、基本概念&quot;">​</a></h2><h3 id="压缩的分类" tabindex="-1">压缩的分类 <a class="header-anchor" href="#压缩的分类" aria-label="Permalink to &quot;压缩的分类&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">类型</th><th style="text-align:center;">说明</th><th style="text-align:left;">示例</th></tr></thead><tbody><tr><td style="text-align:center;">无损压缩</td><td style="text-align:center;">压缩后可以完整还原，不丢失任何信息</td><td style="text-align:left;">ZIP、RAR</td></tr><tr><td style="text-align:center;">有损压缩</td><td style="text-align:center;">压缩后无法完全还原，会丢失部分信息</td><td style="text-align:left;">JPEG、MP3</td></tr></tbody></table><hr><h2 id="二、无损压缩" tabindex="-1">二、无损压缩 <a class="header-anchor" href="#二、无损压缩" aria-label="Permalink to &quot;二、无损压缩&quot;">​</a></h2><h3 id="常见无损压缩格式" tabindex="-1">常见无损压缩格式 <a class="header-anchor" href="#常见无损压缩格式" aria-label="Permalink to &quot;常见无损压缩格式&quot;">​</a></h3><ul><li><strong>ZIP</strong>：最常见的压缩格式</li><li><strong>RAR</strong>：WinRAR 使用的格式</li><li><strong>7z</strong>：7-Zip 使用的格式</li><li><strong>PNG</strong>：图片无损压缩</li><li><strong>GZIP</strong>：Unix/Linux 常用</li></ul><h2 id="三、有损压缩" tabindex="-1">三、有损压缩 <a class="header-anchor" href="#三、有损压缩" aria-label="Permalink to &quot;三、有损压缩&quot;">​</a></h2><h3 id="常见有损压缩格式" tabindex="-1">常见有损压缩格式 <a class="header-anchor" href="#常见有损压缩格式" aria-label="Permalink to &quot;常见有损压缩格式&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">格式</th><th style="text-align:center;">用途</th><th style="text-align:center;">压缩比</th></tr></thead><tbody><tr><td style="text-align:center;">JPEG</td><td style="text-align:center;">图片</td><td style="text-align:center;">高（可调）</td></tr><tr><td style="text-align:center;">MP3</td><td style="text-align:center;">音频</td><td style="text-align:center;">约 1:10</td></tr><tr><td style="text-align:center;">MPEG</td><td style="text-align:center;">视频</td><td style="text-align:center;">很高</td></tr><tr><td style="text-align:center;">AAC</td><td style="text-align:center;">音频</td><td style="text-align:center;">高</td></tr></tbody></table><h2 id="四、图片格式对比" tabindex="-1">四、图片格式对比 <a class="header-anchor" href="#四、图片格式对比" aria-label="Permalink to &quot;四、图片格式对比&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:center;">格式</th><th style="text-align:center;">类型</th><th style="text-align:left;">特点</th><th style="text-align:left;">适用场景</th></tr></thead><tbody><tr><td style="text-align:center;">BMP</td><td style="text-align:center;">无损</td><td style="text-align:left;">未经压缩，文件大</td><td style="text-align:left;">Windows 系统图</td></tr><tr><td style="text-align:center;">PNG</td><td style="text-align:center;">无损</td><td style="text-align:left;">支持透明，压缩比高</td><td style="text-align:left;">网页、图标</td></tr><tr><td style="text-align:center;">JPEG</td><td style="text-align:center;">有损</td><td style="text-align:left;">压缩比高，会失真</td><td style="text-align:left;">照片、复杂图像</td></tr><tr><td style="text-align:center;">GIF</td><td style="text-align:center;">无损</td><td style="text-align:left;">动画支持，256色</td><td style="text-align:left;">简单动画</td></tr><tr><td style="text-align:center;">WebP</td><td style="text-align:center;">可选</td><td style="text-align:left;">支持有损/无损</td><td style="text-align:left;">Web 图像</td></tr></tbody></table><hr><h2 id="五、真题" tabindex="-1">五、真题 <a class="header-anchor" href="#五、真题" aria-label="Permalink to &quot;五、真题&quot;">​</a></h2><p><strong>7.（2025-01，综合题一）</strong> 关于小申的处理方式，以下说法正确的有（ ） ①使用WinZip软件将该文件压缩为&quot;2.zip&quot;；②使用画图软件将文件另存为&quot;2.jpg&quot;；③使用直接修改扩展名的方法将该文件名改为&quot;2.png&quot; A. ②是有损压缩 B. ③是有损压缩 C. ①是无损压缩</p><p><strong>8.（2025-03，综合题一）</strong> 关于数据压缩，以下说法正确的是（ ） A. &quot;1.jpg&quot;文件不可以再次压缩 B. &quot;数据集.rar&quot;文件和其他文件一起压缩成&quot;资料.zip&quot;文件，使用的是有损压缩方法 C. &quot;数据集.rar&quot;文件解压缩后的数据和压缩前的数据完全相同 D. &quot;1.jpg&quot;的文件格式是未经压缩的图像文件格式</p><p><strong>9.（2025-04，综合题一）</strong> 在不改变时长的前提下，机器狗将拍摄的原始视频文件存储为mp4格式，文件的数据存储量显著减少。这属于数据压缩中的（ ） A. 有损压缩 B. 无损压缩</p>',18)])])}const y=e(r,[["render",d]]);export{x as __pageData,y as default};
